import torch
import torch.nn as nn
from transformers import CLIPVisionModel


class SatelliteCLIPClassifier(nn.Module):
    def __init__(self, model_name='openai/clip-vit-large-patch14', num_classes=62, dropout=0.0, head_type='linear', hidden_dim=1024):
        super().__init__()
        self.model_name = model_name
        self.vision_model = CLIPVisionModel.from_pretrained(model_name)
        cfg = self.vision_model.config
        dim = int(getattr(cfg, 'hidden_size', 1024))
        self.feature_dim = dim
        self.head_type = head_type
        if head_type == 'mlp':
            self.classifier = nn.Sequential(
                nn.LayerNorm(dim),
                nn.Dropout(float(dropout)),
                nn.Linear(dim, int(hidden_dim)),
                nn.GELU(),
                nn.Dropout(float(dropout)),
                nn.Linear(int(hidden_dim), num_classes),
            )
        else:
            self.classifier = nn.Sequential(
                nn.Dropout(float(dropout)),
                nn.Linear(dim, num_classes),
            )

    def forward_features(self, x):
        out = self.vision_model(pixel_values=x, return_dict=False)
        return out[1]

    def forward(self, x):
        return self.classifier(self.forward_features(x))


def create_model(model_name='openai/clip-vit-large-patch14', num_classes=62, dropout=0.0, head_type='linear', hidden_dim=1024):
    return SatelliteCLIPClassifier(model_name=model_name, num_classes=num_classes, dropout=dropout, head_type=head_type, hidden_dim=hidden_dim)
